head.script:
scwin.v_workClsCd = "";
scwin.bOnPopUp = false;
scwin.lobranCd = "";
scwin.vCurDate = "";
scwin.vwrkStDt = "";
scwin.vwrkEndDt = "";
scwin.txt_staffNm = "";

scwin.onpageload = function() {
    scwin.lobranCd = $c.ses.getLobranCd();
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.vwrkStDt = scwin.vCurDate.substring(0, 6) + "01";
    scwin.vwrkEndDt = scwin.vCurDate.substring(0, 6) + $c.date.getLastDate(scwin.vCurDate);
    scwin.f_SetDefaultData();
};

scwin.onUdcCompleted = function() {
    udc_wrkDt.setInitDate(scwin.vwrkStDt, scwin.vwrkEndDt);
};

scwin.f_SetDefaultData = function() {
    chb_dailygb.setValue("");
    lc_lobranCd.setValue(scwin.lobranCd);
    lc_lobranCd.setFocus();
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_InitObjects();
};

scwin.f_InitObjects = function() {
    $c.gus.cfInitObjects(lc_lobranCd, udc_wrkDt, udc_staff, chb_dailygb);
    scwin.f_SetDefaultData();
    udc_wrkDt.setInitDate(scwin.vwrkStDt, scwin.vwrkEndDt);
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.f_Retrieve = async function() {
    if (!(await $c.gus.cfValidate([lc_lobranCd, udc_wrkDt]))) {
        return;
    }

    let dailygbVal = chb_dailygb.getValue();
    let isDailyChecked = (dailygbVal != "" && dailygbVal != null);

    if (!isDailyChecked) {
        gr_eqMan.setColumnVisible("workDt", false);
        gr_stvMan.setColumnVisible("workDt", false);
        gr_eqMan.setColumnVisible("fromStHh", false);
        gr_stvMan.setColumnVisible("fromStHh", false);
        gr_eqMan.setColumnVisible("fromEndHh", false);
        gr_stvMan.setColumnVisible("fromEndHh", false);
        gr_eqMan.setColumnVisible("toStHh", false);
        gr_stvMan.setColumnVisible("toStHh", false);
        gr_eqMan.setColumnVisible("toEndHh", false);
        gr_stvMan.setColumnVisible("toEndHh", false);
    } else {
        gr_eqMan.setColumnVisible("workDt", true);
        gr_stvMan.setColumnVisible("workDt", true);
        gr_eqMan.setColumnVisible("fromStHh", true);
        gr_stvMan.setColumnVisible("fromStHh", true);
        gr_eqMan.setColumnVisible("fromEndHh", true);
        gr_stvMan.setColumnVisible("fromEndHh", true);
        gr_eqMan.setColumnVisible("toStHh", true);
        gr_stvMan.setColumnVisible("toStHh", true);
        gr_eqMan.setColumnVisible("toEndHh", true);
        gr_stvMan.setColumnVisible("toEndHh", true);
    }

    ds_condition.set("staffNo", ed_staffNo.getValue().trim());

    await $c.sbm.execute(sbm_retrieve);

    scwin.f_detail(0);
};

scwin.sbm_retrieve_submitdone = async function(e) {
    let eqRowCnt = ds_eqMan.getRowCount();
    let stvRowCnt = ds_stvMan.getRowCount();

    if (eqRowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
    } else {
        let dailygbVal = chb_dailygb.getValue();
        let isDailyChecked = (dailygbVal != "" && dailygbVal != null);
        if (isDailyChecked) {
            scwin.f_detail(0);
        }
    }

    if (stvRowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
    } else {
        let dailygbVal = chb_dailygb.getValue();
        let isDailyChecked = (dailygbVal != "" && dailygbVal != null);
        if (isDailyChecked) {
            scwin.f_detail2(0);
        }
    }
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_retrieveDetail_submitdone = async function(e) {
    let rowCnt = ds_payDetail.getRowCount();
};

scwin.sbm_retrieveDetail_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_detail = async function(row) {
    if (ds_eqMan.getRowCount() > 0) {
        ds_condition2.set("wrkDt", ds_eqMan.getCellData(row, "workDt"));
        ds_condition2.set("staffNo", ds_eqMan.getCellData(row, "staffNo"));
        await $c.sbm.execute(sbm_retrieveDetail);
    }
};

scwin.f_detail2 = async function(row) {
    if (ds_stvMan.getRowCount() > 0) {
        ds_condition2.set("wrkDt", ds_stvMan.getCellData(row, "workDt"));
        ds_condition2.set("staffNo", ds_stvMan.getCellData(row, "staffNo"));
        await $c.sbm.execute(sbm_retrieveDetail);
    }
};

scwin.gr_eqMan_oncellclick = function(rowIndex, columnIndex, columnId) {
    if (rowIndex >= 0) {
        let dailygbVal = chb_dailygb.getValue();
        let isDailyChecked = (dailygbVal != "" && dailygbVal != null);
        if (isDailyChecked) {
            scwin.f_detail(rowIndex);
        }
    }
};

scwin.gr_stvMan_oncellclick = function(rowIndex, columnIndex, columnId) {
    if (rowIndex >= 0) {
        let dailygbVal = chb_dailygb.getValue();
        let isDailyChecked = (dailygbVal != "" && dailygbVal != null);
        if (isDailyChecked) {
            scwin.f_detail2(rowIndex);
        }
    }
};

scwin.ed_staffNo_onblur = function(e) {
    if (ed_staffNo.getValue() == "") {
        scwin.txt_staffNm = "";
    } else {
        scwin.f_openCommonPopUp(1, ed_staffNo.getValue(), scwin.txt_staffNm, "F", "F");
    }
};

scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList;

    switch (disGubun) {
        case 1:
            let arrParam = {};
            arrParam["staffNo"] = pCode;
            arrParam["staffNm"] = pName;
            arrParam["lobranCd"] = lc_lobranCd.getValue();
            arrParam["lobranNm"] = lc_lobranCd.getText();
            arrParam["workPlaceCd"] = "";
            arrParam["jobClsCd"] = "";
            arrParam["dtlJobClsCd"] = "";
            arrParam["positionCd"] = "";
            arrParam["workDt"] = "";
            arrParam["assignYn"] = "";
            arrParam["winCloseTF"] = "T";
            arrParam["dtlJobFlag"] = "1";
            arrParam["wrkStDt"] = ica_wrkStDt.getValue();
            arrParam["wrkEndDt"] = ica_wrkEndDt.getValue();

            rtnList = await $c.win.openPopup("/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.xml", {
                width: 530,
                height: 450,
                modal: true,
                data: arrParam
            });

            if (rtnList != null) {
                ed_staffNo.setValue(rtnList[2]);
                scwin.txt_staffNm = rtnList[3];
            } else {
                ed_staffNo.setValue("");
                scwin.txt_staffNm = "";
            }
            break;
    }
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    } else {
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
    }
};

scwin.f_gridToExcel = function(argGrid, argTitle) {
    $c.data.downloadGridViewExcel(argGrid, {
        fileName: argTitle + ".xlsx",
        sheetName: argTitle
    });
};
